#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int a[N];
        for(int i=0;i<N;i++) scanf("%d",&a[i]);
        bool used[N]; for(int i=0;i<N;i++) used[i]=false;
        int maxIdx=0; for(int i=1;i<N;i++) if(a[i]>a[maxIdx]) maxIdx=i;
        int cur=a[maxIdx]; used[maxIdx]=true; long long ans=cur;
        while(cur!=0){
            int best=-1, bestIdx=-1;
            for(int i=0;i<N;i++) if(!used[i]){
                int val=cur & a[i];
                if(val>best){ best=val; bestIdx=i; }
            }
            if(bestIdx==-1) break;
            used[bestIdx]=true; cur=best; ans+=cur;
        }
        printf("%lld\n",ans);
    }
    return 0;
}

