#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    t = next(it)
    out = []
    for _ in range(t):
        n = next(it)
        a = [next(it) for _ in range(n)]
        used = [False] * n
        max_idx = 0
        for i in range(1, n):
            if a[i] > a[max_idx]:
                max_idx = i
        cur = a[max_idx]
        used[max_idx] = True
        ans = cur
        while cur != 0:
            best = -1
            best_idx = -1
            for i in range(n):
                if not used[i]:
                    val = cur & a[i]
                    if val > best:
                        best = val
                        best_idx = i
            if best_idx == -1:
                break
            used[best_idx] = True
            cur = best
            ans += cur
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

